import { createHash, createHmac, randomUUID } from "crypto";

import { getFounder as getFounderFromSessionCookie } from "@/lib/auth";
import { clientIpFor } from "@/lib/currentsFingerprint";
import { canWrite, WRITE_FORBIDDEN_RESPONSE } from "@/lib/roles";
import type {
  OperatorBet,
  OperatorKillSwitchState,
  OperatorLiveBetsResponse,
  PublicForecast,
} from "@/lib/forecastsTypes";

export const FORECASTS_OPERATOR_BACKEND = (
  process.env.FORECASTS_API_URL ??
  process.env.CURRENTS_API_URL ??
  "http://127.0.0.1:8088"
).replace(/\/+$/, "");

const OPERATOR_HEADER = "x-forecasts-operator";
const OPERATOR_TIMESTAMP_HEADER = "x-forecasts-timestamp";

type StreamingRequestInit = RequestInit & { duplex?: "half" };

function normalizePath(path: string): string {
  return path.startsWith("/") ? path : `/${path}`;
}

export function isOperatorForecastsPath(path: string): boolean {
  const normalizedPath = normalizePath(path);
  return normalizedPath === "/v1/operator" || normalizedPath.startsWith("/v1/operator/");
}

function operatorBackendUrl(path: string, search?: string | URLSearchParams): string {
  const normalizedPath = normalizePath(path);
  if (!isOperatorForecastsPath(normalizedPath)) {
    throw new Error(`operator forecasts proxy refused upstream path: ${normalizedPath}`);
  }

  const url = new URL(`${FORECASTS_OPERATOR_BACKEND}${normalizedPath}`);
  if (search instanceof URLSearchParams) {
    url.search = search.toString();
  } else if (search) {
    url.search = search.startsWith("?") ? search.slice(1) : search;
  }
  return url.toString();
}

function jsonError(error: string, status: number): Response {
  return new Response(JSON.stringify({ error }), {
    status,
    headers: { "content-type": "application/json" },
  });
}

function proxiedJsonHeaders(upstream: Response): Headers {
  const headers = new Headers();
  const contentType = upstream.headers.get("content-type");
  const cacheControl = upstream.headers.get("cache-control");
  const retryAfter = upstream.headers.get("retry-after");

  if (contentType) headers.set("content-type", contentType);
  if (cacheControl) headers.set("cache-control", cacheControl);
  if (retryAfter) headers.set("retry-after", retryAfter);
  return headers;
}

function proxiedSseHeaders(upstream: Response): Headers {
  const headers = new Headers();
  headers.set("content-type", upstream.headers.get("content-type") || "text/event-stream; charset=utf-8");
  headers.set("cache-control", "no-cache, no-transform");
  headers.set("connection", "keep-alive");
  headers.set("x-accel-buffering", "no");
  const retryAfter = upstream.headers.get("retry-after");
  if (retryAfter) headers.set("retry-after", retryAfter);
  return headers;
}

function chunkForwardingStream(body: ReadableStream<Uint8Array> | null): ReadableStream<Uint8Array> | null {
  if (body === null) return null;
  const reader = body.getReader();
  return new ReadableStream<Uint8Array>({
    async pull(controller) {
      const { done, value } = await reader.read();
      if (done) {
        controller.close();
        return;
      }
      if (value) controller.enqueue(value);
    },
    async cancel(reason) {
      await reader.cancel(reason);
    },
  });
}

function proxyResponse(upstream: Response): Response {
  return new Response(upstream.body, {
    status: upstream.status,
    statusText: upstream.statusText,
    headers: proxiedJsonHeaders(upstream),
  });
}

function proxySseResponse(upstream: Response): Response {
  if (!upstream.ok) return proxyResponse(upstream);
  return new Response(chunkForwardingStream(upstream.body), {
    status: upstream.status,
    statusText: upstream.statusText,
    headers: proxiedSseHeaders(upstream),
  });
}

function computeOperatorHmac(
  secret: string,
  options: {
    timestamp: string;
    path: string;
    body: Uint8Array;
  },
): string {
  const bodyHash = createHash("sha256").update(options.body).digest("hex");
  const message = [options.timestamp, normalizePath(options.path), bodyHash].join("\n");
  return createHmac("sha256", secret).update(message, "utf8").digest("hex");
}

function signedOperatorHeaders(req: Request, path: string, body: Uint8Array): Headers | Response {
  const secret = process.env.FORECASTS_OPERATOR_SECRET?.trim();
  if (!secret) return jsonError("operator_secret_not_configured", 500);

  const headers = new Headers();
  const contentType = req.headers.get("content-type");
  const accept = req.headers.get("accept");
  const userAgent = req.headers.get("user-agent");
  const ip = clientIpFor(req);
  const timestamp = String(Date.now() / 1000);
  const digest = computeOperatorHmac(secret, {
    timestamp,
    path,
    body,
  });

  if (contentType) headers.set("content-type", contentType);
  if (accept) headers.set("accept", accept);
  if (userAgent) headers.set("user-agent", userAgent);
  if (ip !== "unknown") headers.set("x-forwarded-for", ip);
  headers.set("x-request-id", req.headers.get("x-request-id") || randomUUID());
  headers.set(OPERATOR_TIMESTAMP_HEADER, timestamp);
  headers.set(OPERATOR_HEADER, digest);
  return headers;
}

export async function getFounderFromSession() {
  return getFounderFromSessionCookie();
}

function operatorCsrfToken(founderId: string): string {
  return process.env.FORECASTS_OPERATOR_CSRF_TOKEN?.trim() || `founder:${founderId}`;
}

async function readBodyForSigning(
  req: Request,
  method: string,
  founder: { id: string },
): Promise<Uint8Array> {
  if (method === "GET" || method === "HEAD") return new Uint8Array();
  const raw = await req.arrayBuffer();
  const text = new TextDecoder().decode(raw).trim();
  let payload: Record<string, unknown> = {};
  if (text) {
    try {
      const parsed = JSON.parse(text);
      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
        payload = parsed as Record<string, unknown>;
      }
    } catch {
      payload = {};
    }
  }
  payload.operator_id = founder.id;
  payload.csrf_token = operatorCsrfToken(founder.id);
  return new TextEncoder().encode(JSON.stringify(payload));
}

function exactArrayBuffer(bytes: Uint8Array): ArrayBuffer {
  return bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength) as ArrayBuffer;
}

function upstreamUnavailable(error: unknown): Response {
  const message = error instanceof Error ? error.message : "unknown upstream failure";
  return new Response(JSON.stringify({ error: "forecasts_operator_upstream_unavailable", detail: message }), {
    status: 502,
    headers: { "content-type": "application/json" },
  });
}

export async function proxyToForecastsOperator(
  req: Request,
  path: string,
  options: {
    method?: "GET" | "POST";
    sse?: boolean;
  } = {},
): Promise<Response> {
  const founder = await getFounderFromSession();
  if (!founder) return jsonError("Not authenticated", 401);
  if (!canWrite(founder.role)) {
    return new Response(JSON.stringify(WRITE_FORBIDDEN_RESPONSE), {
      status: 403,
      headers: { "content-type": "application/json" },
    });
  }
  if (!isOperatorForecastsPath(path)) return jsonError("forecast_operator_proxy_not_found", 404);

  const sourceUrl = new URL(req.url);
  const method = options.method ?? req.method;
  const bodyBytes = await readBodyForSigning(req, method, { id: founder.id });
  const headers = signedOperatorHeaders(req, path, bodyBytes);
  if (headers instanceof Response) return headers;

  const init: StreamingRequestInit = {
    method,
    headers,
    cache: "no-store",
    redirect: "manual",
    signal: req.signal,
  };

  if (method !== "GET" && method !== "HEAD") {
    init.body = new Blob([exactArrayBuffer(bodyBytes)]);
    if (bodyBytes.byteLength > 0) init.duplex = "half";
  }

  try {
    const upstream = await fetch(operatorBackendUrl(path, sourceUrl.search), init);
    return options.sse ? proxySseResponse(upstream) : proxyResponse(upstream);
  } catch (error) {
    return upstreamUnavailable(error);
  }
}

async function fetchOperatorJson<T>(path: string, search?: URLSearchParams): Promise<T> {
  const secret = process.env.FORECASTS_OPERATOR_SECRET?.trim();
  if (!secret) throw new Error("FORECASTS_OPERATOR_SECRET is not configured");
  const body = new Uint8Array();
  const timestamp = String(Date.now() / 1000);
  const headers = new Headers({
    accept: "application/json",
    [OPERATOR_TIMESTAMP_HEADER]: timestamp,
    [OPERATOR_HEADER]: computeOperatorHmac(secret, { timestamp, path, body }),
  });
  const res = await fetch(operatorBackendUrl(path, search), {
    method: "GET",
    headers,
    cache: "no-store",
  });
  if (!res.ok) {
    const detail = await res.text().catch(() => "");
    throw new Error(`Forecasts operator API ${res.status}${detail ? `: ${detail}` : ""}`);
  }
  return res.json() as Promise<T>;
}

export async function listOperatorLiveBets(params: { limit?: number; offset?: number } = {}) {
  const search = new URLSearchParams();
  if (params.limit !== undefined) search.set("limit", String(params.limit));
  if (params.offset !== undefined) search.set("offset", String(params.offset));
  return fetchOperatorJson<OperatorLiveBetsResponse>("/v1/operator/live-bets", search);
}

export async function authorizeLiveForecast(
  id: string,
  body: { operator_id: string; csrf_token: string },
): Promise<PublicForecast> {
  return postOperatorJson<PublicForecast>(`/v1/operator/forecasts/${encodeURIComponent(id)}/authorize-live`, body);
}

export async function confirmLiveBet(
  id: string,
  betId: string,
  body: { operator_id: string; csrf_token: string },
): Promise<OperatorBet> {
  return postOperatorJson<OperatorBet>(
    `/v1/operator/forecasts/${encodeURIComponent(id)}/bets/${encodeURIComponent(betId)}/confirm`,
    body,
  );
}

export async function cancelLiveBet(
  id: string,
  betId: string,
  body: { operator_id: string; csrf_token: string },
): Promise<OperatorBet> {
  return postOperatorJson<OperatorBet>(
    `/v1/operator/forecasts/${encodeURIComponent(id)}/bets/${encodeURIComponent(betId)}/cancel`,
    body,
  );
}

export async function engageKillSwitch(body: {
  operator_id: string;
  reason: string;
  note?: string | null;
  csrf_token: string;
}): Promise<OperatorKillSwitchState> {
  return postOperatorJson<OperatorKillSwitchState>("/v1/operator/kill-switch/engage", body);
}

export async function disengageKillSwitch(body: {
  operator_id: string;
  note: string;
  csrf_token: string;
}): Promise<OperatorKillSwitchState> {
  return postOperatorJson<OperatorKillSwitchState>("/v1/operator/kill-switch/disengage", body);
}

async function postOperatorJson<T>(path: string, body: object): Promise<T> {
  const secret = process.env.FORECASTS_OPERATOR_SECRET?.trim();
  if (!secret) throw new Error("FORECASTS_OPERATOR_SECRET is not configured");
  const rawJson = JSON.stringify(body);
  const raw = new TextEncoder().encode(rawJson);
  const timestamp = String(Date.now() / 1000);
  const headers = new Headers({
    accept: "application/json",
    "content-type": "application/json",
    [OPERATOR_TIMESTAMP_HEADER]: timestamp,
    [OPERATOR_HEADER]: computeOperatorHmac(secret, { timestamp, path, body: raw }),
  });
  const res = await fetch(operatorBackendUrl(path), {
    method: "POST",
    headers,
    body: rawJson,
    cache: "no-store",
  });
  if (!res.ok) {
    const detail = await res.text().catch(() => "");
    throw new Error(`Forecasts operator API ${res.status}${detail ? `: ${detail}` : ""}`);
  }
  return res.json() as Promise<T>;
}

"""Live Polymarket CLOB adapter for Forecasts.

The Polymarket CLOB currently signs orders as EIP-712 payloads and uses L2
HMAC credentials for authenticated trading requests. This wrapper intentionally
delegates those moving parts to Polymarket's SDK when live trading is actually
enabled; importing this module never constructs a wallet or contacts the CLOB.
"""

from __future__ import annotations

import asyncio
import os
from decimal import Decimal, InvalidOperation
from typing import Any, Literal

from pydantic import BaseModel, Field

from noosphere.forecasts._polymarket_client import PolymarketGammaClient


class PolymarketLiveOrder(BaseModel):
    external_order_id: str
    status: str
    filled_size: Decimal = Decimal("0")
    average_price: Decimal | None = None
    raw_payload: dict[str, Any] = Field(default_factory=dict)


class PolymarketLiveClient(PolymarketGammaClient):
    """Async live-trading facade over the Polymarket CLOB SDK."""

    def __init__(
        self,
        *,
        base: str = "https://clob.polymarket.com",
        private_key: str | None = None,
        chain_id: int = 137,
        signature_type: int = 0,
        funder: str | None = None,
        tick_size: str = "0.01",
        neg_risk: bool = False,
        timeout_s: float = 15.0,
    ) -> None:
        super().__init__(base=base, timeout_s=timeout_s)
        self._private_key = (
            private_key or os.getenv("POLYMARKET_PRIVATE_KEY", "")
        ).strip()
        self._chain_id = chain_id
        self._signature_type = signature_type
        self._funder = funder
        self._tick_size = tick_size
        self._neg_risk = neg_risk
        self._sdk_client: Any | None = None
        self.wallet_address = _wallet_address_or_none(self._private_key)

    @classmethod
    def from_env(cls) -> PolymarketLiveClient:
        return cls(
            base=os.getenv("POLYMARKET_CLOB_BASE", "https://clob.polymarket.com"),
            private_key=os.getenv("POLYMARKET_PRIVATE_KEY", ""),
            chain_id=int(os.getenv("POLYMARKET_CHAIN_ID", "137")),
            signature_type=int(os.getenv("POLYMARKET_SIGNATURE_TYPE", "0")),
            funder=os.getenv("POLYMARKET_FUNDER_ADDRESS", "").strip() or None,
            tick_size=os.getenv("POLYMARKET_DEFAULT_TICK_SIZE", "0.01"),
            neg_risk=os.getenv("POLYMARKET_DEFAULT_NEG_RISK", "").strip().lower()
            in {"1", "true", "yes", "y"},
        )

    async def place_order(
        self,
        condition_id: str,
        outcome_index: int,
        side: Literal["BUY", "SELL"],
        size: Decimal | float | str,
        price: Decimal | float | str,
        order_type: str,
    ) -> PolymarketLiveOrder:
        """Create, EIP-712 sign, and post an order through the CLOB SDK.

        Polymarket's current docs describe `createAndPostOrder` /
        `createOrder` + `postOrder` over `tokenID`. The local market mirror
        stores `conditionId`; callers should pass the resolved CLOB token id
        when it is available and fall back to the condition id only for mocks.
        """

        payload = await asyncio.to_thread(
            self._sdk_place_order,
            condition_id,
            outcome_index,
            side,
            size,
            price,
            order_type,
        )
        return _order_from_payload(payload)

    async def cancel_order(self, order_id: str) -> PolymarketLiveOrder:
        payload = await asyncio.to_thread(self._sdk_cancel_order, order_id)
        return _order_from_payload(
            payload,
            fallback_order_id=order_id,
            fallback_status="CANCELLED",
        )

    async def get_order(self, order_id: str) -> PolymarketLiveOrder:
        payload = await asyncio.to_thread(self._sdk_get_order, order_id)
        return _order_from_payload(payload, fallback_order_id=order_id)

    def _sdk_place_order(
        self,
        token_id: str,
        _outcome_index: int,
        side: str,
        size: Decimal | float | str,
        price: Decimal | float | str,
        order_type: str,
    ) -> dict[str, Any]:
        client = self._ensure_sdk_client()
        sdk_side = _sdk_side(side)
        sdk_order_type = _sdk_order_type(order_type)
        order_args = _sdk_order_args(
            token_id=token_id,
            price=float(_decimal(price)),
            size=float(_decimal(size)),
            side=sdk_side,
        )
        options = {"tickSize": self._tick_size, "negRisk": self._neg_risk}

        method = getattr(client, "createAndPostOrder", None) or getattr(
            client,
            "create_and_post_order",
            None,
        )
        if method is not None:
            return _payload_dict(method(order_args, options, sdk_order_type))

        create_order = getattr(client, "createOrder", None) or getattr(
            client,
            "create_order",
            None,
        )
        post_order = getattr(client, "postOrder", None) or getattr(
            client,
            "post_order",
            None,
        )
        if create_order is None or post_order is None:
            raise RuntimeError(
                "Polymarket SDK does not expose create/post order methods expected "
                "by the CLOB docs"
            )
        signed_order = create_order(order_args, options)
        return _payload_dict(post_order(signed_order, sdk_order_type))

    def _sdk_cancel_order(self, order_id: str) -> dict[str, Any]:
        client = self._ensure_sdk_client()
        method = getattr(client, "cancelOrder", None) or getattr(client, "cancel", None)
        if method is None:
            raise RuntimeError("Polymarket SDK does not expose cancelOrder/cancel")
        return _payload_dict(method(order_id))

    def _sdk_get_order(self, order_id: str) -> dict[str, Any]:
        client = self._ensure_sdk_client()
        method = getattr(client, "getOrder", None) or getattr(client, "get_order", None)
        if method is None:
            raise RuntimeError("Polymarket SDK does not expose getOrder/get_order")
        return _payload_dict(method(order_id))

    def _ensure_sdk_client(self) -> Any:
        if not self._private_key:
            raise RuntimeError("POLYMARKET_PRIVATE_KEY is required for live trading")
        if self._sdk_client is not None:
            return self._sdk_client

        try:
            from py_clob_client.client import ClobClient
        except ImportError as exc:  # pragma: no cover - depends on optional live SDK.
            raise RuntimeError(
                "py-clob-client is required for Polymarket live trading"
            ) from exc

        kwargs: dict[str, Any] = {
            "host": self._base,
            "key": self._private_key,
            "chain_id": self._chain_id,
        }
        if self._signature_type is not None:
            kwargs["signature_type"] = self._signature_type
        if self._funder:
            kwargs["funder"] = self._funder
        client = ClobClient(**kwargs)

        derive = getattr(client, "create_or_derive_api_creds", None) or getattr(
            client,
            "createOrDeriveApiKey",
            None,
        )
        set_creds = getattr(client, "set_api_creds", None) or getattr(
            client,
            "setApiCreds",
            None,
        )
        if derive is not None and set_creds is not None:
            set_creds(derive())

        self._sdk_client = client
        return client


def _wallet_address_or_none(private_key: str) -> str | None:
    if not private_key:
        return None
    try:
        from eth_account import Account
    except ImportError:  # pragma: no cover - optional live dependency.
        return None
    return str(Account.from_key(private_key).address)


def _sdk_order_args(*, token_id: str, price: float, size: float, side: Any) -> Any:
    try:
        from py_clob_client.clob_types import OrderArgs
    except ImportError:  # pragma: no cover - handled before live use.
        return {
            "tokenID": token_id,
            "token_id": token_id,
            "price": price,
            "size": size,
            "side": side,
        }
    try:
        return OrderArgs(price=price, size=size, side=side, token_id=token_id)
    except TypeError:
        return OrderArgs(price=price, size=size, side=side, tokenID=token_id)


def _sdk_side(side: str) -> Any:
    normalized = side.upper()
    try:
        from py_clob_client.order_builder.constants import BUY, SELL

        return BUY if normalized == "BUY" else SELL
    except ImportError:  # pragma: no cover - handled before live use.
        return normalized


def _sdk_order_type(order_type: str) -> Any:
    normalized = order_type.upper()
    try:
        from py_clob_client.clob_types import OrderType
    except ImportError:  # pragma: no cover - handled before live use.
        return normalized
    return getattr(OrderType, normalized, normalized)


def _order_from_payload(
    payload: dict[str, Any],
    *,
    fallback_order_id: str | None = None,
    fallback_status: str | None = None,
) -> PolymarketLiveOrder:
    order_id = _str_first(
        payload,
        "external_order_id",
        "orderID",
        "order_id",
        "id",
    ) or fallback_order_id
    if not order_id:
        raise RuntimeError("Polymarket order response missing order id")
    status = _str_first(payload, "status", "state") or fallback_status or "SUBMITTED"
    return PolymarketLiveOrder(
        external_order_id=order_id,
        status=str(status),
        filled_size=_decimal_first(
            payload,
            "filled_size",
            "filledSize",
            "filledAmount",
            "filled_amount",
            "matchedAmount",
        ),
        average_price=_decimal_first_or_none(
            payload,
            "average_price",
            "averagePrice",
            "avgPrice",
            "price",
        ),
        raw_payload=payload,
    )


def _payload_dict(value: Any) -> dict[str, Any]:
    if isinstance(value, dict):
        return value
    if hasattr(value, "model_dump"):
        dumped = value.model_dump()
        return dumped if isinstance(dumped, dict) else {"value": dumped}
    if hasattr(value, "dict"):
        dumped = value.dict()
        return dumped if isinstance(dumped, dict) else {"value": dumped}
    if hasattr(value, "__dict__"):
        return dict(value.__dict__)
    raise RuntimeError(
        f"unexpected Polymarket SDK payload type: {type(value).__name__}"
    )


def _str_first(payload: dict[str, Any], *keys: str) -> str | None:
    for key in keys:
        value = payload.get(key)
        if value is not None and str(value).strip():
            return str(value).strip()
    return None


def _decimal_first(payload: dict[str, Any], *keys: str) -> Decimal:
    return _decimal_first_or_none(payload, *keys) or Decimal("0")


def _decimal_first_or_none(payload: dict[str, Any], *keys: str) -> Decimal | None:
    for key in keys:
        value = payload.get(key)
        if value is None:
            continue
        try:
            return _decimal(value)
        except ValueError:
            continue
    return None


def _decimal(value: Any) -> Decimal:
    try:
        return Decimal(str(value))
    except (InvalidOperation, ValueError, TypeError) as exc:
        raise ValueError(f"not a decimal value: {value!r}") from exc

"""Persistent Forecasts scheduler status for readiness checks."""

from __future__ import annotations

import json
import os
import tempfile
from dataclasses import asdict, is_dataclass
from datetime import datetime, timezone
from decimal import Decimal
from pathlib import Path
from typing import Any


STATUS_FILENAME = "forecasts_status.json"
DEFAULT_STATUS_PATH = Path("/var/lib/theseus") / STATUS_FILENAME


def status_path_from_env() -> Path:
    explicit = os.environ.get("FORECASTS_STATUS_PATH", "").strip()
    if explicit:
        return Path(explicit)
    legacy = os.environ.get("FORECASTS_RESOLUTION_STATUS_PATH", "").strip()
    if legacy:
        return Path(legacy)
    data_dir = os.environ.get("NOOSPHERE_DATA_DIR", "").strip()
    if data_dir:
        return Path(data_dir) / STATUS_FILENAME
    return DEFAULT_STATUS_PATH


def utc_now_iso() -> str:
    return datetime.now(timezone.utc).replace(microsecond=0).isoformat().replace(
        "+00:00",
        "Z",
    )


def parse_utc_iso(value: object) -> datetime | None:
    if not isinstance(value, str) or not value.strip():
        return None
    raw = value.strip()
    if raw.endswith("Z"):
        raw = f"{raw[:-1]}+00:00"
    try:
        parsed = datetime.fromisoformat(raw)
    except ValueError:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _payload(report: Any) -> dict[str, Any]:
    if is_dataclass(report):
        return asdict(report)
    if isinstance(report, dict):
        return dict(report)
    raise TypeError(f"unsupported status report type: {type(report).__name__}")


def _json_default(value: Any) -> Any:
    if isinstance(value, datetime):
        return value.astimezone(timezone.utc).replace(microsecond=0).isoformat().replace(
            "+00:00",
            "Z",
        )
    if isinstance(value, Decimal):
        return float(value)
    raise TypeError(f"object of type {type(value).__name__} is not JSON serializable")


def write_status(report: Any, path: Path | None = None) -> Path:
    target = Path(path) if path is not None else status_path_from_env()
    target.parent.mkdir(parents=True, exist_ok=True)
    payload = _payload(report)

    fd, tmp_name = tempfile.mkstemp(
        prefix=f".{target.name}.",
        suffix=".tmp",
        dir=str(target.parent),
        text=True,
    )
    tmp_path = Path(tmp_name)
    try:
        with os.fdopen(fd, "w", encoding="utf-8") as fh:
            json.dump(payload, fh, indent=2, sort_keys=True, default=_json_default)
            fh.write("\n")
            fh.flush()
            os.fsync(fh.fileno())
        os.replace(tmp_path, target)
    finally:
        if tmp_path.exists():
            tmp_path.unlink()
    return target


def read_status(path: Path | None = None) -> dict[str, Any]:
    target = Path(path) if path is not None else status_path_from_env()
    return json.loads(target.read_text(encoding="utf-8"))

