33	function operatorBackendUrl(path: string, search?: string | URLSearchParams): string {
34	  const normalizedPath = normalizePath(path);
35	  if (!isOperatorForecastsPath(normalizedPath)) {
36	    throw new Error(`operator forecasts proxy refused upstream path: ${normalizedPath}`);
37	  }
38	
39	  const url = new URL(`${FORECASTS_OPERATOR_BACKEND}${normalizedPath}`);
40	  if (search instanceof URLSearchParams) {
41	    url.search = search.toString();
42	  } else if (search) {
