55	function proxiedJsonHeaders(upstream: Response): Headers {
56	  const headers = new Headers();
57	  const contentType = upstream.headers.get("content-type");
58	  const cacheControl = upstream.headers.get("cache-control");
59	  const retryAfter = upstream.headers.get("retry-after");
60	
61	  if (contentType) headers.set("content-type", contentType);
62	  if (cacheControl) headers.set("cache-control", cacheControl);
63	  if (retryAfter) headers.set("retry-after", retryAfter);
64	  return headers;
65	}
66	
67	function proxiedSseHeaders(upstream: Response): Headers {
68	  const headers = new Headers();
69	  headers.set("content-type", upstream.headers.get("content-type") || "text/event-stream; charset=utf-8");
70	  headers.set("cache-control", "no-cache, no-transform");
71	  headers.set("connection", "keep-alive");
72	  headers.set("x-accel-buffering", "no");
73	  const retryAfter = upstream.headers.get("retry-after");
74	  if (retryAfter) headers.set("retry-after", retryAfter);
75	  return headers;
76	}
77	
78	function chunkForwardingStream(body: ReadableStream<Uint8Array> | null): ReadableStream<Uint8Array> | null {
79	  if (body === null) return null;
80	  const reader = body.getReader();
81	  return new ReadableStream<Uint8Array>({
82	    async pull(controller) {
83	      const { done, value } = await reader.read();
84	      if (done) {
85	        controller.close();
86	        return;
87	      }
88	      if (value) controller.enqueue(value);
89	    },
90	    async cancel(reason) {
91	      await reader.cancel(reason);
92	    },
93	  });
94	}
95	
96	function proxyResponse(upstream: Response): Response {
97	  return new Response(upstream.body, {
98	    status: upstream.status,
99	    statusText: upstream.statusText,
100	    headers: proxiedJsonHeaders(upstream),
101	  });
102	}
103	
104	function proxySseResponse(upstream: Response): Response {
105	  if (!upstream.ok) return proxyResponse(upstream);
106	  return new Response(chunkForwardingStream(upstream.body), {
107	    status: upstream.status,
108	    statusText: upstream.statusText,
109	    headers: proxiedSseHeaders(upstream),
110	  });
111	}
112	
113	function computeOperatorHmac(
114	  secret: string,
115	  options: {
116	    timestamp: string;
117	    path: string;
118	    body: Uint8Array;
119	  },
120	): string {
121	  const bodyHash = createHash("sha256").update(options.body).digest("hex");
122	  const message = [options.timestamp, normalizePath(options.path), bodyHash].join("\n");
123	  return createHmac("sha256", secret).update(message, "utf8").digest("hex");
124	}
125	
126	function signedOperatorHeaders(req: Request, path: string, body: Uint8Array): Headers | Response {
127	  const secret = process.env.FORECASTS_OPERATOR_SECRET?.trim();
128	  if (!secret) return jsonError("operator_secret_not_configured", 500);
129	
130	  const headers = new Headers();
131	  const contentType = req.headers.get("content-type");
132	  const accept = req.headers.get("accept");
133	  const userAgent = req.headers.get("user-agent");
134	  const ip = clientIpFor(req);
135	  const timestamp = String(Date.now() / 1000);
136	  const digest = computeOperatorHmac(secret, {
137	    timestamp,
138	    path,
139	    body,
140	  });
141	
142	  if (contentType) headers.set("content-type", contentType);
143	  if (accept) headers.set("accept", accept);
144	  if (userAgent) headers.set("user-agent", userAgent);
145	  if (ip !== "unknown") headers.set("x-forwarded-for", ip);
146	  headers.set("x-request-id", req.headers.get("x-request-id") || randomUUID());
147	  headers.set(OPERATOR_TIMESTAMP_HEADER, timestamp);
148	  headers.set(OPERATOR_HEADER, digest);
149	  return headers;
150	}
151	
152	export async function getFounderFromSession() {
153	  return getFounderFromSessionCookie();
154	}
155	
156	function operatorCsrfToken(founderId: string): string {
157	  return process.env.FORECASTS_OPERATOR_CSRF_TOKEN?.trim() || `founder:${founderId}`;
158	}
159	
160	async function readBodyForSigning(
161	  req: Request,
162	  method: string,
163	  founder: { id: string },
164	): Promise<Uint8Array> {
165	  if (method === "GET" || method === "HEAD") return new Uint8Array();
166	  const raw = await req.arrayBuffer();
167	  const text = new TextDecoder().decode(raw).trim();
168	  let payload: Record<string, unknown> = {};
169	  if (text) {
170	    try {
171	      const parsed = JSON.parse(text);
172	      if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
173	        payload = parsed as Record<string, unknown>;
174	      }
175	    } catch {
176	      payload = {};
177	    }
178	  }
179	  payload.operator_id = founder.id;
180	  payload.csrf_token = operatorCsrfToken(founder.id);
181	  return new TextEncoder().encode(JSON.stringify(payload));
182	}
183	
184	function exactArrayBuffer(bytes: Uint8Array): ArrayBuffer {
185	  return bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength) as ArrayBuffer;
186	}
187	
188	function upstreamUnavailable(error: unknown): Response {
189	  const message = error instanceof Error ? error.message : "unknown upstream failure";
190	  return new Response(JSON.stringify({ error: "forecasts_operator_upstream_unavailable", detail: message }), {
191	    status: 502,
192	    headers: { "content-type": "application/json" },
193	  });
194	}
195	
196	export async function proxyToForecastsOperator(
197	  req: Request,
198	  path: string,
199	  options: {
200	    method?: "GET" | "POST";
201	    sse?: boolean;
202	  } = {},
203	): Promise<Response> {
204	  const founder = await getFounderFromSession();
205	  if (!founder) return jsonError("Not authenticated", 401);
